dashboard.definition:
{
  "title": "Sample Dashboard 3 \u2014 Application Portal",
  "description": "Sample portal-style dashboard with 8 large category cards. Every icon is a bundled SVG referenced directly via splunk.image (no icon_library.icon_library viz). Demonstrates the SVG-asset pattern for navigation hubs.",
  "defaults": {},
  "dataSources": {},
  "inputs": {},
  "visualizations": {
    "viz_canvas_bg": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#F5F5F7",
        "strokeColor": "transparent"
      }
    },
    "viz_header_title": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#1D1D1F",
        "fontFamily": "Helvetica",
        "fontSize": "extraLarge",
        "markdown": "# Sample 3 \u2014 Application Portal\n\n*Navigation-hub layout \u00b7 8 categories \u00b7 click a card to navigate*"
      }
    },
    "viz_header_subtitle": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#6E6E73",
        "fontFamily": "Helvetica",
        "fontSize": "small",
        "markdown": "Icons rendered directly from the bundled SVG catalog via `splunk.image` \u2014 no `icon_library.icon_library` viz instances on this page. Each card's icon URL points to `/static/app/icon_library/icons/<category>/<name>.svg`."
      }
    },
    "viz_shadow_0": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#E8E8ED",
        "strokeColor": "transparent"
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_card_0": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#FFFFFF",
        "strokeColor": "#D2D2D7",
        "strokeWidth": 1
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_icon_0": {
      "type": "splunk.image",
      "options": {
        "backgroundColor": "transparent",
        "src": "/static/app/icon_library/icons/action/dashboard.svg"
      }
    },
    "viz_text_0": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#1D1D1F",
        "fontFamily": "Helvetica",
        "fontSize": "default",
        "markdown": "**Dashboards**\n\n*Visualize anything*"
      }
    },
    "viz_stat_0": {
